const models = $input.all()
  .map((item) => item.json)
  .sort((a, b) => (b.workerCount || 0) - (a.workerCount || 0));

if (models.length === 0) {
  throw new Error('No Sogni LLM models are available right now. Try again later.');
}

const triggerJson = $('Ask For Secret Object').first().json || {};
const rawSecretObject = String(
  triggerJson.secretObject ??
  triggerJson['Secret Object'] ??
  triggerJson.body?.secretObject ??
  triggerJson.body?.['Secret Object'] ??
  triggerJson.formData?.secretObject ??
  triggerJson.formData?.['Secret Object'] ??
  ''
).trim();

const normalize = (value) => String(value || '')
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, ' ')
  .trim();

const catalog = {
  umbrella: { aliases: ['umbrella'], category: 'accessory' },
  toaster: { aliases: ['toaster'], category: 'appliance' },
  skateboard: { aliases: ['skateboard'], category: 'vehicle' },
  telescope: { aliases: ['telescope'], category: 'instrument' },
  pineapple: { aliases: ['pineapple'], category: 'food' },
  backpack: { aliases: ['backpack'], category: 'container' },
  candle: { aliases: ['candle'], category: 'home item' },
  keyboard: { aliases: ['keyboard', 'computer keyboard'], category: 'electronics' },
  bicycle: { aliases: ['bicycle', 'bike'], category: 'vehicle' },
  mug: { aliases: ['mug', 'coffee mug'], category: 'drinkware' }
};

const candidateObjects = Object.keys(catalog);
const aliasToCanonical = new Map();
for (const [name, info] of Object.entries(catalog)) {
  aliasToCanonical.set(normalize(name), name);
  for (const alias of info.aliases) {
    aliasToCanonical.set(normalize(alias), name);
  }
}

const secretObject = aliasToCanonical.get(normalize(rawSecretObject));
if (!secretObject) {
  throw new Error(`Secret object must be one of: ${candidateObjects.join(', ')}`);
}

const bestModel = models[0];
const systemPrompt = `You are playing a 20-questions style guessing game. The secret object is one of these candidates: ${candidateObjects.join(', ')}. You do not know which one. Use exactly one tool call per move. Use ask_question for short yes/no property questions. Use make_guess when you are confident. You have at most 20 moves total. Never answer directly without a tool call.`;
const userPrompt = 'Begin the game. Use your first move now.';
const fallbackPrompt = `${userPrompt} Candidate objects: ${candidateObjects.join(', ')}. Moves remaining: 20.`;

const tools = [
  {
    type: 'function',
    function: {
      name: 'ask_question',
      description: 'Ask one short yes/no question about the secret object.',
      parameters: {
        type: 'object',
        properties: {
          question: {
            type: 'string',
            description: 'A concise yes/no question about the object.'
          }
        },
        required: ['question']
      }
    }
  },
  {
    type: 'function',
    function: {
      name: 'make_guess',
      description: 'Make a final guess for the secret object when you are confident.',
      parameters: {
        type: 'object',
        properties: {
          guess: {
            type: 'string',
            description: 'Your best guess for the secret object.'
          }
        },
        required: ['guess']
      }
    }
  }
];

const messages = [
  {
    role: 'system',
    content: systemPrompt
  },
  {
    role: 'user',
    content: userPrompt
  }
];

return {
  json: {
    secretObject,
    candidateObjects,
    modelId: bestModel.id,
    modelName: bestModel.label || bestModel.id,
    workerCount: bestModel.workerCount || 0,
    systemPrompt,
    fallbackPrompt,
    messages,
    tools,
    toolChoice: 'required',
    maxMoves: 20,
    movesUsed: 0,
    moveLog: [],
    outcome: 'playing',
    isComplete: 0
  }
};

const state = $input.first().json;
const toolCall = Array.isArray(state.toolCalls) ? state.toolCalls[0] : undefined;

if (!toolCall) {
  const contentPreview = String(state.content || '').trim().slice(0, 220);
  throw new Error(
    `Expected a tool call, but the model returned none. Model: ${state.modelId || 'unknown'}. ` +
    `This usually means the selected model ignored tool calling or your installed Sogni node does not support Messages JSON / Tools JSON yet. ` +
    `Previous content: ${contentPreview || '(empty)'}`
  );
}

const normalize = (value) => String(value || '')
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, ' ')
  .trim();

const catalog = {
  umbrella: {
    aliases: ['umbrella'],
