    usedForDrink: true,
    usedWithComputer: false,
    givesLight: false,
    storage: false,
    optical: false,
    materials: ['ceramic']
  }
};

const secretObject = String(state.secretObject || '');
const secret = catalog[secretObject];
if (!secret) {
  throw new Error(`Unknown secret object: ${secretObject || '(empty)'}`);
}

const aliasToCanonical = new Map();
for (const [name, info] of Object.entries(catalog)) {
  aliasToCanonical.set(normalize(name), name);
  for (const alias of info.aliases) {
    aliasToCanonical.set(normalize(alias), name);
  }
}

let args = {};
try {
  args = JSON.parse(toolCall.function.arguments || '{}');
} catch {
  args = {};
}

const q = (text) => normalize(text);
const hasAny = (text, terms) => terms.some((term) => text.includes(term));
const yesNo = (value, clue) => ({ answer: value ? 'yes' : 'no', clue });
const unknown = (clue) => ({ answer: 'unknown', clue });

const answerQuestion = (question) => {
  const questionText = q(question);
  if (!questionText) return unknown('Empty question');

  for (const [name, info] of Object.entries(catalog)) {
    if ([name, ...info.aliases].some((alias) => questionText.includes(q(alias)))) {
      return yesNo(name === secretObject, `Name check against ${name}`);
    }
  }

  if (hasAny(questionText, ['electric', 'battery', 'plug', 'power'])) return yesNo(secret.electric, 'Power source');
  if (hasAny(questionText, ['outside', 'outdoor', 'outdoors'])) return yesNo(secret.outdoors, 'Outdoor use');
  if (hasAny(questionText, ['inside', 'indoor', 'indoors'])) return yesNo(secret.indoors, 'Indoor use');
  if (hasAny(questionText, ['wear', 'worn', 'on your back'])) return yesNo(secret.wearable, 'Wearable');
  if (hasAny(questionText, ['handheld', 'hand held', 'one hand', 'hold in your hand'])) return yesNo(secret.handheld, 'Handheld');
  if (hasAny(questionText, ['portable', 'carry around'])) return yesNo(secret.portable, 'Portable');
  if (hasAny(questionText, ['wheel', 'wheels', 'roll'])) return yesNo(secret.wheels, 'Wheels');
  if (hasAny(questionText, ['handle', 'handles'])) return yesNo(secret.hasHandle, 'Handle');
  if (hasAny(questionText, ['kitchen', 'cook', 'toast'])) return yesNo(secret.kitchen, 'Kitchen use');
  if (hasAny(questionText, ['food', 'eat', 'edible', 'fruit'])) return yesNo(secret.edible, 'Edible');
  if (hasAny(questionText, ['drink from', 'drinking', 'cup', 'coffee'])) return yesNo(secret.usedForDrink, 'Drink use');
  if (hasAny(questionText, ['ride', 'transport', 'travel'])) return yesNo(secret.usedForTransport, 'Transport use');
  if (hasAny(questionText, ['rain', 'weather', 'storm'])) return yesNo(secret.weather, 'Weather use');
  if (hasAny(questionText, ['light', 'burn', 'flame'])) return yesNo(secret.givesLight, 'Light source');
  if (hasAny(questionText, ['computer', 'type', 'typing', 'keys'])) return yesNo(secret.usedWithComputer, 'Computer use');
  if (hasAny(questionText, ['look at stars', 'star', 'sky', 'far away', 'magnify', 'telescope'])) return yesNo(secret.optical, 'Optical use');
  if (hasAny(questionText, ['bag', 'store things', 'hold things', 'storage'])) return yesNo(secret.storage, 'Storage use');
  if (hasAny(questionText, ['metal'])) return yesNo(secret.materials.includes('metal'), 'Material');
  if (hasAny(questionText, ['wood'])) return yesNo(secret.materials.includes('wood'), 'Material');
  if (hasAny(questionText, ['fabric', 'cloth'])) return yesNo(secret.materials.includes('fabric'), 'Material');
  if (hasAny(questionText, ['plastic'])) return yesNo(secret.materials.includes('plastic'), 'Material');
  if (hasAny(questionText, ['glass'])) return yesNo(secret.materials.includes('glass'), 'Material');
  if (hasAny(questionText, ['ceramic'])) return yesNo(secret.materials.includes('ceramic'), 'Material');
  if (hasAny(questionText, ['wax'])) return yesNo(secret.materials.includes('wax'), 'Material');
  if (hasAny(questionText, ['vehicle'])) return yesNo(secret.category === 'vehicle', 'Category');
  if (hasAny(questionText, ['appliance'])) return yesNo(secret.category === 'appliance', 'Category');
  if (hasAny(questionText, ['instrument'])) return yesNo(secret.category === 'instrument', 'Category');
  if (hasAny(questionText, ['food item', 'food'])) return yesNo(secret.category === 'food', 'Category');
  if (hasAny(questionText, ['drinkware'])) return yesNo(secret.category === 'drinkware', 'Category');
  if (hasAny(questionText, ['electronics', 'electronic'])) return yesNo(secret.category === 'electronics', 'Category');
  if (hasAny(questionText, ['container'])) return yesNo(secret.category === 'container', 'Category');
  if (hasAny(questionText, ['accessory'])) return yesNo(secret.category === 'accessory', 'Category');

  return unknown('Ask about category, use, material, power, portability, wheels, handle, weather, kitchen, food, light, computer use, or transport.');
};

const moveNumber = Number(state.movesUsed || 0) + 1;
const maxMoves = Number(state.maxMoves || 20);
const remainingMoves = Math.max(maxMoves - moveNumber, 0);

let toolResult;
let actionText;
let resultText;
let guessedCorrectly = false;

if (toolCall.function.name === 'ask_question') {
  const question = String(args.question || '').trim();
  const answer = answerQuestion(question);
  toolResult = {
    question,
    answer: answer.answer,
    clue: answer.clue,
    remaining_moves: remainingMoves
  };
  actionText = `Asked: ${question || '(empty question)'}`;
  resultText = `${answer.answer.toUpperCase()}${answer.clue ? ` - ${answer.clue}` : ''}`;
} else if (toolCall.function.name === 'make_guess') {
  const rawGuess = String(args.guess || '').trim();
  const guessedObject = aliasToCanonical.get(normalize(rawGuess)) || normalize(rawGuess);
  guessedCorrectly = guessedObject === secretObject;
  toolResult = {
    guess: rawGuess || guessedObject || '(empty guess)',
    correct: guessedCorrectly,
    remaining_moves: remainingMoves,
    message: guessedCorrectly ? 'Correct guess.' : 'Wrong guess.'
  };
  actionText = `Guessed: ${rawGuess || guessedObject || '(empty guess)'}`;
  resultText = guessedCorrectly ? 'Correct' : 'Wrong';
} else {
  throw new Error(`Unsupported tool call: ${toolCall.function.name}`);
}

const priorMessages = Array.isArray(state.messages) ? state.messages : [];
const followUpMessages = [
  ...priorMessages,
  {
    role: 'assistant',
    content: state.content || null,
    tool_calls: state.toolCalls
  },
  {
    role: 'tool',
    tool_call_id: toolCall.id,
    name: toolCall.function.name,
    content: JSON.stringify(toolResult)
  }
];

const moveLog = [
  ...(Array.isArray(state.moveLog) ? state.moveLog : []),
  {
    move: moveNumber,
    tool: toolCall.function.name,
    action: actionText,
    result: resultText
  }
];

const gameOver = guessedCorrectly || moveNumber >= maxMoves;
const outcome = guessedCorrectly ? 'guessed' : gameOver ? 'out_of_moves' : 'playing';
const transcriptSummary = moveLog
  .map((entry) => `${entry.move}. ${entry.action} => ${entry.result}`)
  .join('\n');
const fallbackPrompt = `Continue the guessing game. Candidate objects: ${(state.candidateObjects || []).join(', ')}. Moves used: ${moveNumber}/${maxMoves}. Transcript so far:\n${transcriptSummary}\nUse exactly one tool now. If you are confident, call make_guess. Otherwise call ask_question with one short yes/no question.`;

return {
  json: {
    ...state,
    messages: followUpMessages,
    movesUsed: moveNumber,
    remainingMoves,
    moveLog,
    lastToolResult: toolResult,
    fallbackPrompt,
    outcome,
    isComplete: gameOver ? 1 : 0
  }
};

const state = $input.first().json;

const escapeHtml = (value) => String(value || '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');

const secretObject = String(state.secretObject || 'unknown object');
const modelId = String(state.modelId || 'unknown-model');
const movesUsed = Number(state.movesUsed || 0);
const maxMoves = Number(state.maxMoves || 20);
const outcome = String(state.outcome || 'unknown');
const title = outcome === 'guessed'
  ? `Guessed ${secretObject} in ${movesUsed} moves`
  : `Out of moves. Secret object: ${secretObject}`;
const summary = outcome === 'guessed'
  ? 'Sogni LLM guessed the secret object.'
  : `Sogni LLM did not guess the secret object within ${maxMoves} moves.`;
const moveLog = Array.isArray(state.moveLog) ? state.moveLog : [];
const transcriptHtml = moveLog.length
  ? moveLog
      .map((entry) => `<strong>${entry.move}.</strong> ${escapeHtml(entry.action)}<br><em>${escapeHtml(entry.result)}</em>`)
      .join('<br><br>')
  : 'No moves recorded.';

return {
  json: {
    ...state,
    completionTitle: title,
    completionMessage: `${escapeHtml(summary)}<br><br><strong>Secret object:</strong> ${escapeHtml(secretObject)}<br><strong>Moves used:</strong> ${movesUsed}/${maxMoves}<br><strong>Model:</strong> ${escapeHtml(modelId)}<br><br>${transcriptHtml}`
  }
};
